<script>
    export default {
        name: 'settings',
        props: {
            textAlign : {
                type : String ,
                default : "text-left"
            }
        },
        data() {
            return {
                crumbs: [],
                canSeeModules : true,
                enable_website: Spark.state.currentTeam.enable_website
            }
        },
        methods: {

          checkCanSeeModulesForMonthlyYearlySubscription(){
            if(Nova.app.currentTeam.last_subscription && Nova.app.currentTeam.last_subscription.stripe_plan == 'monthly-yearly'){
              this.canSeeModules = false;
            }else{
              this.canSeeModules = true;
            }
          },
            goTo(type) {


                if (Spark.state.currentTeam.current_billing_plan == 'team-free' && (type == 'users' || type == 'website')) {
                    if (type == 'users') {
                        this.$toasted.show(Nova.app.__('Your account on the free plan must be upgraded to access to manage users'), { type: 'error' })
                    }
                    if (type == 'website') {
                        this.$toasted.show(Nova.app.__('Your account on the free plan must be upgraded to reach to manage the website'), { type: 'error' })
                    }
                    return;
                }

                if (type == 'terms' || type == 'activity-logs' ||  type == 'sources' || type == 'highlights' || type == 'users' || type == 'hotel-amenities') {
                    this.$router.push('resources/' + type)
                } else {
                    this.$router.push({name: 'settings.' + type})
                }

            }
        },
        mounted() {

            let lang = Nova.config.local ;
            lang == 'en' ? this.textAlign = 'text-left' : this.textAlign = 'text-right' ;

            this.crumbs = [
                {
                    text: 'Home',
                    to: '/dashboards/main',
                },
                {
                    text: 'Settings',
                    to: '#',
                }
            ];
            this.checkCanSeeModulesForMonthlyYearlySubscription();
        },

    }
</script>

